def save_gpx(activity_id, date, lats, lngs):
    GPX_DIR.mkdir(parents=True, exist_ok=True)
    n = len(lats)
    pts = "\n".join(
        '      <trkpt lat="{:.5f}" lon="{:.5f}"></trkpt>'.format(lats[i], lngs[i])
        for i in range(n)
    )
    gpx = (
        '<?xml version="1.0" encoding="UTF-8"?>\n'
        '<gpx version="1.1" creator="jeffry.running" '
        'xmlns="http://www.topografix.com/GPX/1/1">\n'
        '  <metadata><time>{}</time></metadata>\n'
        '  <trk>\n    <trkseg>\n{}\n    </trkseg>\n  </trk>\n'
        '</gpx>'
    ).format(date, pts)
    out = GPX_DIR / f"{activity_id}.gpx"
    out.write_text(gpx)


def main():
    activities = json.loads(DATA_PATH.read_text())
    updated = 0

    for a in activities:
        aid = a["id"]
        if aid not in GPS:
            print(f"  — No GPS update needed: {aid}")
            continue

        gps = GPS[aid]
        lats = gps["lat"]
        lngs = gps["lng"]

        # Ensure equal length
        n = min(len(lats), len(lngs))
        lats = lats[:n]
        lngs = lngs[:n]

        a["track_lat"] = lats
        a["track_lng"] = lngs

        save_gpx(aid, a["date"], lats, lngs)
        print(f"  ✓ {aid[:8]}… — {a['date'][:10]} — {n} GPS pts, GPX written")
        updated += 1

    DATA_PATH.write_text(json.dumps(activities, indent=2))
    print(f"\nDone. {updated} activities updated, activities.json written.")


if __name__ == "__main__":
    main()
